UPDATE user_notification
notification_id = #{notificationId}, user_id = #{userId}, is_read = #{isRead}, read_time = #{readTime},
WHERE id = #{id}

mapper.select:
SELECT un.id, un.notification_id, un.user_id, un.is_read, un.read_time, un.create_time
FROM user_notification un

    INNER JOIN system_notification sn ON un.notification_id = sn.id


    un.user_id = #{userId}

        AND un.is_read = #{isRead}


        AND (sn.title LIKE CONCAT('%', #{keyword}, '%') OR sn.content LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY un.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM user_notification un

    INNER JOIN system_notification sn ON un.notification_id = sn.id


    un.user_id = #{userId}

        AND un.is_read = #{isRead}


        AND (sn.title LIKE CONCAT('%', #{keyword}, '%') OR sn.content LIKE CONCAT('%', #{keyword}, '%'))
